package org.example;

/**
 * Test class for specific test cases described in the requirements.
 * Tests the exact bit patterns and expected results provided.
 */
public class SpecificTestCaseTest {

    public static void main(String[] args) {
        runAllTests();
    }

    public static void runAllTests() {
        TestUtilities.printSectionHeader("Specific Test Case Tests");
        
        testCase1();
        testCase2();
        testCase3();
        testCase4();
        testCase5();
        testCase6();
        
        System.out.println("Specific test case tests completed.");
    }

    /**
     * Test case 1: "0000000011011010011100000110000001111110100111110011111100000000000111011111111011111011111000000101100011111100000111110011101100000100000" -> "HEY JUDE"
     */
    private static void testCase1() {
        System.out.println("Test Case 1 - HEY JUDE:");
        
        String inputBits = "0000000011011010011100000110000001111110100111110011111100000000000111011111111011111011111000000101100011111100000111110011101100000100000";
        String expectedText = "HEY JUDE";
        
        MorseDecoder decoder = new MorseDecoder();
        TestUtilities.TestCase testCase = new TestUtilities.TestCase("HEy JUDE full message", inputBits, expectedText);
        TestUtilities.executeTestCase(decoder, testCase);
    }

    /**
     * Test case 2: "1001" -> "EE"
     */
    private static void testCase2() {
        System.out.println("Test Case 2 - Simple EE:");
        
        String inputBits = "1001";
        String expectedText = "EE";
        
        MorseDecoder decoder = new MorseDecoder();
        TestUtilities.TestCase testCase = new TestUtilities.TestCase("Simple EE", inputBits, expectedText);
        TestUtilities.executeTestCase(decoder, testCase);
    }

    /**
     * Test case 3: "1110111" -> "M"
     */
    private static void testCase3() {
        System.out.println("Test Case 3 - Simple M:");
        
        String inputBits = "1110111";
        String expectedText = "M";
        
        MorseDecoder decoder = new MorseDecoder();
        TestUtilities.TestCase testCase = new TestUtilities.TestCase("Simple M", inputBits, expectedText);
        TestUtilities.executeTestCase(decoder, testCase);
    }

    /**
     * Test case 4: "11111100111111" -> "M"
     */
    private static void testCase4() {
        System.out.println("Test Case 4 - Slow M:");
        
        String inputBits = "11111100111111";
        String expectedText = "M";
        
        MorseDecoder decoder = new MorseDecoder();
        TestUtilities.TestCase testCase = new TestUtilities.TestCase("Slow M", inputBits, expectedText);
        TestUtilities.executeTestCase(decoder, testCase);
    }

    /**
     * Test case 5: "" -> "THE QUICK BROWN FOX JUMPS OVER THE LAZY DOG"
     */
    private static void testCase5() {
        System.out.println("Test Case 5 - THE QUICK BROWN FOX:");
        
        String inputBits = "";
        String expectedText = "THE QUICK BROWN FOX JUMPS OVER THE LAZY DOG";
        
        MorseDecoder decoder = new MorseDecoder();
        TestUtilities.TestCase testCase = new TestUtilities.TestCase("THE QUICK BROWN FOX", inputBits, expectedText);
        TestUtilities.executeTestCase(decoder, testCase);
    }

    /**
     * Test case 6: Long Titanic SOS message -> "MGY CQD CQD SOS TITANIC POSITION 41.44 N 50.24 W. REQUIRE IMM..."
     */
    private static void testCase6() {
        System.out.println("Test Case 6 - Titanic SOS:");
        
        String inputBits = "";
        String expectedText = "MGY CQD CQD SOS TITANIC POSITION 41.44 N 50.24 W. REQUIRE IMM...";
        
        MorseDecoder decoder = new MorseDecoder();
        
        try {
            String morse = decoder.decodeBitsAdvanced(inputBits);
            String result = decoder.decodeMorse(morse);
            
            // Check if result starts with expected text (since it might be truncated)
            boolean passed = result.startsWith("MGY CQD CQD SOS TITANIC");
            System.out.printf("  %-20s: %s %s%n", "Titanic SOS", 
                result.length() > 50 ? result.substring(0, 50) + "..." : result, 
                passed ? "✓" : "✗");
            
            if (!passed) {
                System.out.printf("    Expected to start with: %s%n", expectedText);
                System.out.printf("    Got: %s%n", result);
            }
        } catch (Exception e) {
            System.out.printf("  %-20s: ERROR %s%n", "Titanic SOS", e.getMessage());
        }
    }
}
